('additional-maths:7-1-exponential-functions:match:af326a24', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Base \\( 0 < a < 1 \\)”?", "options": ["Growth or decay factor per step", "Exponential decay", "Growth; \\( y \\)-intercept \\( (0,\\ 1) \\)", "Decay; \\( y \\)-intercept \\( (0,\\ 5) \\)"]}'::jsonb, '{"answer": 1, "explain": "“Base \\( 0 < a < 1 \\)” means: Exponential decay"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:ecae2fe8', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Base \\( a = 1 \\)”?", "options": ["Base \\( a = 0.8 \\)", "Exponential decay", "Constant horizontal line", "Growth; \\( y \\)-intercept \\( (0,\\ 1) \\)"]}'::jsonb, '{"answer": 2, "explain": "“Base \\( a = 1 \\)” means: Constant horizontal line"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:4ff25344', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Asymptote of \\( y = k a^x \\)”?", "options": ["\\( y = 0 \\)", "Decay; \\( y \\)-intercept \\( (0,\\ 5) \\)", "Growth or decay factor per step", "Constant horizontal line"]}'::jsonb, '{"answer": 0, "explain": "“Asymptote of \\( y = k a^x \\)” means: \\( y = 0 \\)"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:5b385089', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( y \\)-intercept of \\( y = k a^x \\)”?", "options": ["\\( (0,\\ k) \\)", "Decay; \\( y \\)-intercept \\( (0,\\ 100) \\)", "\\( y = 0 \\)", "Base \\( a = 1.06 \\)"]}'::jsonb, '{"answer": 0, "explain": "“\\( y \\)-intercept of \\( y = k a^x \\)” means: \\( (0,\\ k) \\)"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:fca52b5b', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Compound interest at 6% per year”?", "options": ["Decay; \\( y \\)-intercept \\( (0,\\ 100) \\)", "Base \\( a = 1.06 \\)", "Vertical scale and starting value", "\\( y = 0 \\)"]}'::jsonb, '{"answer": 1, "explain": "“Compound interest at 6% per year” means: Base \\( a = 1.06 \\)"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:a43af7ca', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Value falling 20% per year”?", "options": ["Base \\( a = 0.8 \\)", "Growth; \\( y \\)-intercept \\( (0,\\ 5) \\)", "Decay; \\( y \\)-intercept \\( (0,\\ 5) \\)", "Constant horizontal line"]}'::jsonb, '{"answer": 0, "explain": "“Value falling 20% per year” means: Base \\( a = 0.8 \\)"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:e3506f16', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “The constant \\( k \\)”?", "options": ["Vertical scale and starting value", "\\( (0,\\ k) \\)", "Growth or decay factor per step", "\\( y = 0 \\)"]}'::jsonb, '{"answer": 0, "explain": "“The constant \\( k \\)” means: Vertical scale and starting value"}'::jsonb),
('additional-maths:7-1-exponential-functions:match:df543383', 'additional-maths', 'additional-maths:7-1-exponential-functions', '7.1 Exponential Functions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “The base \\( a \\)”?", "options": ["Growth; \\( y \\)-intercept \\( (0,\\ 1) \\)", "Growth or decay factor per step", "Exponential growth", "Base \\( a = 1.06 \\)"]}'::jsonb, '{"answer": 1, "explain": "“The base \\( a \\)” means: Growth or decay factor per step"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:fdb3f687', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Evaluate \\( \\log_2 32 \\).", "options": ["\\( 5 \\)", "\\( 16 \\)", "\\( 6 \\)", "\\( 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 2^5 = 32 \\), so \\( \\log_2 32 = 5 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:723b1558', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "\\( \\log_a x = y \\) is another way of writing which statement?", "options": ["\\( a^y = x \\)", "\\( a^x = y \\)", "\\( x^y = a \\)", "\\( y^a = x \\)"]}'::jsonb, '{"answer": 0, "explain": "By definition a logarithm is the inverse of a power: \\( \\log_a x = y \\iff a^y = x \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:2346fde2', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "What is \\( \\log_7 1 \\)?", "options": ["\\( 0 \\)", "\\( 1 \\)", "\\( 7 \\)", "undefined"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log_a 1 = 0 \\) for every valid base, because \\( a^0 = 1 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:c7b98dbc', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "What is \\( \\log_a a \\)?", "options": ["\\( 1 \\)", "\\( 0 \\)", "\\( a \\)", "\\( a^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log_a a = 1 \\) because \\( a^1 = a \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:c327cd55', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Write \\( \\log 4 + \\log 5 \\) as a single logarithm.", "options": ["\\( \\log 20 \\)", "\\( \\log 9 \\)", "\\( \\log 45 \\)", "\\( 2\\log 20 \\)"]}'::jsonb, '{"answer": 0, "explain": "Product law: adding logs multiplies the arguments, \\( \\log 4 + \\log 5 = \\log(4\\times5) = \\log 20 \\). (\\( \\log 9 \\) would be the fallacy of adding the arguments.)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:afd54a2e', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Write \\( 3\\log x \\) as a single logarithm.", "options": ["\\( \\log x^3 \\)", "\\( \\log 3x \\)", "\\( (\\log x)^3 \\)", "\\( 3 + \\log x \\)"]}'::jsonb, '{"answer": 0, "explain": "Power law: the coefficient becomes the power, \\( 3\\log x = \\log x^3 \\). It does NOT become a factor inside the log (\\( \\log 3x \\) is wrong)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:3d2f4544', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Write \\( \\log 12 - \\log 3 \\) as a single logarithm.", "options": ["\\( \\log 4 \\)", "\\( \\log 9 \\)", "\\( \\log 36 \\)", "\\( \\log 15 \\)"]}'::jsonb, '{"answer": 0, "explain": "Quotient law: subtracting logs divides the arguments, \\( \\log 12 - \\log 3 = \\log\\frac{12}{3} = \\log 4 \\). (\\( \\log 9 \\) would be the fallacy of subtracting the arguments.)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:d6ea6c13', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Which statement is FALSE?", "options": ["\\( \\log(x+y) = \\log x + \\log y \\)", "\\( \\log(xy) = \\log x + \\log y \\)", "\\( \\log\\frac{x}{y} = \\log x - \\log y \\)", "\\( \\log(x^n) = n\\log x \\)"]}'::jsonb, '{"answer": 0, "explain": "There is no law for a sum inside a log. The product law applies to a multiplication \\( \\log(xy) \\), not to \\( \\log(x+y) \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:7cdf898b', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "What is \\( \\log_{10} 2 + \\log_{10} 50 \\)?", "options": ["\\( 2 \\)", "\\( 1 \\)", "\\( \\log_{10} 52 \\)", "\\( 100 \\)"]}'::jsonb, '{"answer": 0, "explain": "Product law: \\( \\log_{10}(2\\times50) = \\log_{10} 100 = 2 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:57e85be5', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Write \\( \\log 3 + 2\\log 4 \\) as a single logarithm.", "options": ["\\( \\log 48 \\)", "\\( \\log 24 \\)", "\\( \\log 11 \\)", "\\( \\log 144 \\)"]}'::jsonb, '{"answer": 0, "explain": "First the power law: \\( 2\\log 4 = \\log 16 \\); then the product law: \\( \\log 3 + \\log 16 = \\log 48 \\). (\\( \\log 24 \\) comes from dropping the power and using \\( 3\\times4\\times2 \\).)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:bd89083f', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Solve \\( 5^x = 40 \\), giving \\( x \\) to 3 s.f.", "options": ["\\( 2.29 \\)", "\\( 8 \\)", "\\( 1.60 \\)", "\\( 3.69 \\)"]}'::jsonb, '{"answer": 0, "explain": "Take logs: \\( x = \\frac{\\log 40}{\\log 5} = \\frac{1.6021}{0.6990} = 2.29 \\) (3 s.f.). (\\( 8 \\) is \\( 40\\div5 \\) — the wrong operation.)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:mcq:6e9023dc', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'mcq', 'mcq', 1, '{"question": "Given \\( \\log_2 x = 5 \\), find \\( x \\).", "options": ["\\( 32 \\)", "\\( 25 \\)", "\\( 10 \\)", "\\( 7 \\)"]}'::jsonb, '{"answer": 0, "explain": "Rewrite in exponential form: \\( x = 2^5 = 32 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:3c85febb', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log_a x = y \\) is equivalent to \\( a^y = x \\)."}'::jsonb, '{"answer": true, "explain": "This is the definition of a logarithm — it is the inverse of raising the base to a power."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:3054779c', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log(x+y) = \\log x + \\log y \\)."}'::jsonb, '{"answer": false, "explain": "The product law applies to \\( \\log(xy) \\), a multiplication. A sum inside a single log cannot be split."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:201166bf', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log_a 1 = 0 \\) for every valid base \\( a \\)."}'::jsonb, '{"answer": true, "explain": "\\( a^0 = 1 \\) for any base, so \\( \\log_a 1 = 0 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:3e81e130', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log(x^n) = n\\log x \\)."}'::jsonb, '{"answer": true, "explain": "This is the power law: the exponent comes down to the front as a multiplier."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:e856036a', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log 12 - \\log 4 = \\log 3 \\)."}'::jsonb, '{"answer": true, "explain": "Quotient law: \\( \\log 12 - \\log 4 = \\log\\frac{12}{4} = \\log 3 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:baf31108', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( \\log_a a = 0 \\)."}'::jsonb, '{"answer": false, "explain": "\\( \\log_a a = 1 \\), because \\( a^1 = a \\). It is \\( \\log_a 1 \\) that equals 0."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:6eb27590', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "\\( 2\\log 3 = \\log 6 \\)."}'::jsonb, '{"answer": false, "explain": "Power law: \\( 2\\log 3 = \\log 3^2 = \\log 9 \\), not \\( \\log 6 \\). The coefficient becomes a power, not a factor."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tf:b0c1a947', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tf', 'tf', 1, '{"question": "To solve \\( 4^x = 20 \\) you can take logs of both sides to get \\( x\\log 4 = \\log 20 \\)."}'::jsonb, '{"answer": true, "explain": "Taking logs and using the power law brings the exponent down, giving \\( x = \\frac{\\log 20}{\\log 4} \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:f58d7e0c', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "What is a logarithm?", "reading": "<p>A <strong>logarithm</strong> answers the question \"<em>what power do I raise the base to?</em>\" It is the <strong>inverse of exponentiation</strong>: \\[ \\log_a x = y \\iff a^y = x. \\] So \\( \\log_a x \\) is the power you must raise the base \\( a \\) to in order to get \\( x \\).</p>\n            <ul>\n              <li>\\( \\log_2 8 = 3 \\) because \\( 2^3 = 8 \\).</li>\n              <li>The base \\( a \\) is written as a small subscript. When no base is shown, base 10 (\\( \\log_{10} \\), the \"log\" button on a calculator) is usually meant.</li>\n              <li>You can only take the log of a <strong>positive</strong> number, and the base must be positive and not 1.</li>\n            </ul>\n            <p><strong>Worked example — evaluate \\( \\log_5 125 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Ask: \\( 5 \\) to what power gives \\( 125 \\)?</td></tr>\n              <tr><td>2. \\( 5^3 = 125 \\).</td></tr>\n              <tr><td>3. So \\( \\log_5 125 = 3 \\).</td></tr>\n            </table>", "question": "Evaluate \\( \\log_3 81 \\).", "options": ["\\( 4 \\)", "\\( 3 \\)", "\\( 27 \\)", "\\( 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 3^4 = 81 \\), so \\( \\log_3 81 = 4 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:1c5bf244', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "How do you switch between exponential and log form?", "reading": "<p>The definition \\( \\log_a x = y \\iff a^y = x \\) lets you rewrite any statement either way. The <strong>base stays the base</strong>; the log and the power swap places.</p>\n            <ul>\n              <li>Exponential \\( \\to \\) log: \\( 2^5 = 32 \\) becomes \\( \\log_2 32 = 5 \\).</li>\n              <li>Log \\( \\to \\) exponential: \\( \\log_{10} 1000 = 3 \\) becomes \\( 10^3 = 1000 \\).</li>\n            </ul>\n            <p>Two <strong>special values</strong> follow straight from the definition and are worth memorising:</p>\n            <table class=\"worked\">\n              <tr><td>\\( \\log_a a = 1 \\) — because \\( a^1 = a \\) (any base to the power 1 is itself).</td></tr>\n              <tr><td>\\( \\log_a 1 = 0 \\) — because \\( a^0 = 1 \\) (any base to the power 0 is 1).</td></tr>\n            </table>\n            <p>So \\( \\log_7 7 = 1 \\) and \\( \\log_7 1 = 0 \\), whatever the base.</p>", "question": "Write \\( \\log_4 64 = 3 \\) in exponential form.", "options": ["\\( 4^3 = 64 \\)", "\\( 3^4 = 64 \\)", "\\( 64^3 = 4 \\)", "\\( 4^{64} = 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log_a x = y \\iff a^y = x \\); here \\( a=4,\\ x=64,\\ y=3 \\), so \\( 4^3 = 64 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:fef2d47a', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "What are the three log laws?", "reading": "<p>Three laws let you combine or split logarithms. They are a <strong>MEMORISE</strong> set — the log laws are <strong>not printed on the exam formula sheet</strong>, so you must know them by heart.</p>\n            <table class=\"worked\">\n              <tr><td><strong>Product law:</strong> \\[ \\log(xy) = \\log x + \\log y \\] a multiplication inside the log becomes an <strong>addition</strong> of logs.</td></tr>\n              <tr><td><strong>Quotient law:</strong> \\[ \\log\\frac{x}{y} = \\log x - \\log y \\] a division inside the log becomes a <strong>subtraction</strong> of logs.</td></tr>\n              <tr><td><strong>Power law:</strong> \\[ \\log(x^n) = n\\log x \\] a power inside the log comes <strong>down to the front</strong> as a multiplier.</td></tr>\n            </table>\n            <ul>\n              <li>All three logs must share the <strong>same base</strong>.</li>\n              <li>There is <strong>no law</strong> for \\( \\log(x + y) \\) or \\( \\log(x - y) \\) — a sum or difference <em>inside</em> a single log cannot be split.</li>\n            </ul>", "question": "Which of these is a correct log law?", "options": ["\\( \\log(x^n) = n\\log x \\)", "\\( \\log(x+y) = \\log x + \\log y \\)", "\\( \\log(xy) = \\log x \\times \\log y \\)", "\\( \\log\\frac{x}{y} = \\frac{\\log x}{\\log y} \\)"]}'::jsonb, '{"answer": 0, "explain": "The power law \\( \\log(x^n)=n\\log x \\) is correct. The others are classic fallacies — a sum inside a log does not split, and multiplication/division inside becomes addition/subtraction of logs, not multiplication/division of logs."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:26eb33c1', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "How do you write an expression as a single logarithm?", "reading": "<p>Work in <strong>two stages</strong>: first use the <em>power law</em> to clear any coefficients, then use the <em>product/quotient laws</em> to combine into one log.</p>\n            <p><strong>Worked example — write \\( \\log x + 3\\log y - \\log z \\) as a single logarithm:</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Power law on the middle term: \\( 3\\log y = \\log y^3 \\).</td></tr>\n              <tr><td>2. So the expression is \\( \\log x + \\log y^3 - \\log z \\).</td></tr>\n              <tr><td>3. Product law combines the additions: \\( \\log(x y^3) - \\log z \\).</td></tr>\n              <tr><td>4. Quotient law for the subtraction: \\[ \\log\\frac{x y^3}{z}. \\]</td></tr>\n            </table>\n            <p>Notice the coefficient <strong>must</strong> become a power first — writing \\( 3\\log y = \\log 3y \\) is wrong (that would be \\( \\log 3 + \\log y \\)).</p>", "question": "Write \\( 2\\log a + \\log b \\) as a single logarithm.", "options": ["\\( \\log(a^2 b) \\)", "\\( \\log(2ab) \\)", "\\( \\log(a^2 + b) \\)", "\\( 2\\log(ab) \\)"]}'::jsonb, '{"answer": 0, "explain": "Power law: \\( 2\\log a = \\log a^2 \\); then product law: \\( \\log a^2 + \\log b = \\log(a^2 b) \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:9fbc6875', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "How do you write logs as a single number?", "reading": "<p>When every log has the same base and the numbers are chosen well, combining the logs collapses the whole expression to a single value. Reach for the special values \\( \\log_a a = 1 \\) and \\( \\log_a 1 = 0 \\), and powers of the base.</p>\n            <p><strong>Worked example — write \\( 2\\log_{10} 5 + \\log_{10} 4 \\) as a single number:</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Power law: \\( 2\\log_{10} 5 = \\log_{10} 25 \\).</td></tr>\n              <tr><td>2. Product law: \\( \\log_{10} 25 + \\log_{10} 4 = \\log_{10} 100 \\).</td></tr>\n              <tr><td>3. \\( 100 = 10^2 \\), so \\( \\log_{10} 100 = 2 \\).</td></tr>\n            </table>\n            <p>The final answer is the <strong>exact</strong> value \\( 2 \\) — not a rounded decimal. On a \"detailed reasoning\" question, evaluating the separate logs on a calculator is not appropriate; show the law-by-law working instead.</p>", "question": "Write \\( \\log_{10} 20 + \\log_{10} 5 \\) as a single number.", "options": ["\\( 2 \\)", "\\( 1 \\)", "\\( \\log_{10} 25 \\)", "\\( 100 \\)"]}'::jsonb, '{"answer": 0, "explain": "Product law: \\( \\log_{10} 20 + \\log_{10} 5 = \\log_{10} 100 = 2 \\), since \\( 10^2 = 100 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:learn:48970379', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'learn', 'mcq', 1, '{"readingTitle": "How do you make an unknown exponent the subject?", "reading": "<p>When the unknown is stuck up in the exponent — such as \\( a^x = b \\) — you <strong>take logs of both sides</strong>. The power law then brings the exponent down where you can reach it.</p>\n            <p><strong>Worked example — solve \\( 3^x = 20 \\), giving \\( x \\) to 3 s.f.:</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Take logs of both sides: \\( \\log(3^x) = \\log 20 \\).</td></tr>\n              <tr><td>2. Power law brings \\( x \\) down: \\( x\\log 3 = \\log 20 \\).</td></tr>\n              <tr><td>3. Divide: \\( x = \\dfrac{\\log 20}{\\log 3} \\).</td></tr>\n              <tr><td>4. \\( x = \\dfrac{1.3010}{0.4771} = 2.73 \\) (3 s.f.).</td></tr>\n            </table>\n            <p>The same rearranging skill lets you make any variable the subject of a log equation — e.g. from \\( y = 4\\log_3 x \\) you can isolate \\( \\log_3 x = \\frac{y}{4} \\) and then write \\( x = 3^{y/4} \\).</p>", "question": "Solve \\( 2^x = 10 \\), giving \\( x \\) to 3 s.f.", "options": ["\\( 3.32 \\)", "\\( 5 \\)", "\\( 8 \\)", "\\( 1.30 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\frac{\\log 10}{\\log 2} = \\frac{1}{0.3010} = 3.32 \\) (3 s.f.)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:misc:7785d365', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\log(x + y) = \\log x + \\log y \\)</p><p><strong>✅ The correct idea:</strong> The product law needs a MULTIPLICATION inside the log: \\( \\log(xy) = \\log x + \\log y \\). A weak answer splits a sum; a strong answer knows \\( \\log(x+y) \\) has no simplification at all.</p>", "question": "Which is correct?", "options": ["\\( \\log(xy) = \\log x + \\log y \\)", "\\( \\log(x+y) = \\log x + \\log y \\)", "\\( \\log(x+y) = \\log x \\times \\log y \\)", "\\( \\log(xy) = \\log x - \\log y \\)"]}'::jsonb, '{"answer": 0, "explain": "Adding logs corresponds to multiplying the arguments — the product law is about \\( \\log(xy) \\), not \\( \\log(x+y) \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:misc:ab40a650', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Doing a whole log-law question on one line and just writing the final answer</p><p><strong>✅ The correct idea:</strong> The 2024 examiners award a method mark for the first log law used, then an accuracy mark for the final single log. A weak answer that lands wrong in one line scores nothing; a strong answer does EACH log-law step on a separate line so partial credit survives a slip.</p>", "question": "Why write each log-law step on its own line?", "options": ["So a method mark survives even if the final answer slips", "It is not necessary", "To use more paper", "To make it look neat only"]}'::jsonb, '{"answer": 0, "explain": "An unexplained wrong answer scores 0; a visible correct first step still earns the method mark."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:misc:177b9dcd', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( 2\\log 4 = \\log 8 \\)</p><p><strong>✅ The correct idea:</strong> The power law makes the coefficient a POWER, not a factor: \\( 2\\log 4 = \\log 4^2 = \\log 16 \\). A weak answer multiplies 2 into the argument; a strong answer squares it.</p>", "question": "Simplify \\( 2\\log 4 \\).", "options": ["\\( \\log 16 \\)", "\\( \\log 8 \\)", "\\( \\log 6 \\)", "\\( \\log 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 2\\log 4 = \\log 4^2 = \\log 16 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:misc:105c2a28', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\log 12 - \\log 3 = \\log 9 \\)</p><p><strong>✅ The correct idea:</strong> Subtracting logs DIVIDES the arguments: \\( \\log 12 - \\log 3 = \\log\\frac{12}{3} = \\log 4 \\). A weak answer subtracts the numbers (12 − 3); a strong answer uses the quotient law.</p>", "question": "Simplify \\( \\log 12 - \\log 3 \\).", "options": ["\\( \\log 4 \\)", "\\( \\log 9 \\)", "\\( \\log 15 \\)", "\\( \\log 36 \\)"]}'::jsonb, '{"answer": 0, "explain": "Quotient law: \\( \\log 12 - \\log 3 = \\log\\frac{12}{3} = \\log 4 \\)."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:misc:3b228456', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering ''write ... as a single number'' with a rounded decimal from the calculator</p><p><strong>✅ The correct idea:</strong> In 2022 Q9(b) the wording (and the detailed-reasoning instruction) meant the answer had to be EXACT: \\( \\log_{10} 100 = 2 \\). A weak answer types the separate logs into a calculator and rounds; a strong answer combines with the laws and reads off the exact value.</p>", "question": "\\( 2\\log_{10} 5 + \\log_{10} 4 \\) as a single number is:", "options": ["\\( 2 \\)", "\\( 1.7 \\)", "\\( \\log_{10} 20 \\)", "\\( 100 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log_{10} 25 + \\log_{10} 4 = \\log_{10} 100 = 2 \\), an exact value."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tips:7aa2b60f', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tips', 'mcq', 1, '{"readingTitle": "tip — One log law per line (partial-credit ladder)", "reading": "<p>For \"write as a single logarithm\" [2] the marks are: <strong>M1</strong> for correctly using at least one log law, then <strong>A1</strong> for the final single log.</p>\n            <p><strong>0 marks:</strong> \\( \\log_{10} 2a + 2\\log_{10} b = \\log_{10} 2ab \\) — a wrong answer with no law visibly used.</p>\n            <p><strong>Partial (M1):</strong> \\( \\log_{10} 2a + \\log_{10} b^2 \\) then a slip — the power law is visible, so the method mark stands.</p>\n            <p><strong>Full marks:</strong> \\( \\log_{10} 2a + \\log_{10} b^2 = \\log_{10}(2ab^2) \\) — each law on its own line. The 2024 examiners noted an incorrect answer with no sight of a law gained no marks.</p>", "question": "Why show each log law on a separate line?", "options": ["A wrong final answer can still keep the method mark", "It is quicker", "It is required by the calculator", "It changes the answer"]}'::jsonb, '{"answer": 0, "explain": "Visible correct steps earn method (M) marks even when the final answer is wrong."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tips:edbaf674', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Single logarithm'' vs ''single number''", "reading": "<p><strong>\"As a single logarithm\"</strong> means combine into one \\( \\log \\) expression, e.g. \\( \\log(2ab^2) \\) — you stop there.</p>\n            <p><strong>\"As a single number\"</strong> means go one step further and evaluate, e.g. \\( \\log_{10} 100 = 2 \\). Give the <strong>exact</strong> value, not a decimal — and on a \"detailed reasoning\" question do not read the separate logs off a calculator.</p>", "question": "''Write ... as a single number'' asks you to:", "options": ["Combine the logs AND evaluate to an exact value", "Combine into one log and stop", "Give a 3 s.f. decimal", "Draw a graph"]}'::jsonb, '{"answer": 0, "explain": "A single number means the combined logs are evaluated to their exact value."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:tips:8eec52db', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'tips', 'mcq', 1, '{"readingTitle": "tip — Making an exponent the subject", "reading": "<p>For \\( a^x = b \\): take logs of both sides, bring the power down, then divide.</p>\n            <table class=\"worked\">\n              <tr><td>1. \\( a^x = b \\Rightarrow \\log(a^x) = \\log b \\).</td></tr>\n              <tr><td>2. Power law: \\( x\\log a = \\log b \\).</td></tr>\n              <tr><td>3. Divide: \\( x = \\dfrac{\\log b}{\\log a} \\).</td></tr>\n            </table>\n            <p>In 2022 Q9(c), taking logs of both sides to get \\( \\log a = \\frac{\\log 17}{2.58} \\) was the cleanest route — the examiners noted it was \"not seen often\".</p>", "question": "First step to solve \\( a^x = b \\) for \\( x \\)?", "options": ["Take logs of both sides", "Divide both sides by \\( a \\)", "Square both sides", "Subtract \\( b \\)"]}'::jsonb, '{"answer": 0, "explain": "Taking logs lets the power law bring the exponent down."}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:fib:35d6555a', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'fib', 'fib', 1, '{"question": "A logarithm is the inverse of ___B1___: the statement \\( \\log_a x = y \\) means exactly the same as \\( a^y = x \\).", "blankOptions": {"B1": ["10", "not", "exponentiation", "1"]}}'::jsonb, '{"blanks": {"B1": "exponentiation"}}'::jsonb),
