('additional-maths:7-2-logarithms-and-the-log-laws:fib:e92992e1', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'fib', 'fib', 2, '{"question": "The product law turns a multiplication inside a log into an ___B1___ of two logs; the quotient law turns a division into a ___B2___.", "blankOptions": {"B1": ["separate", "power", "addition", "exponentiation"], "B2": ["multiplication", "subtraction", "logs", "10"]}}'::jsonb, '{"blanks": {"B1": "addition", "B2": "subtraction"}}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:fib:2b0ec176', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'fib', 'fib', 1, '{"question": "The power law \\( \\log(x^n) = n\\log x \\) brings the ___B1___ down to the front as a multiplier.", "blankOptions": {"B1": ["power", "index", "10", "logs"]}}'::jsonb, '{"blanks": {"B1": "power"}}'::jsonb),
