('additional-maths:7-2-logarithms-and-the-log-laws:match:93a0c14d', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quotient law”?", "options": ["\\( 3 \\)", "\\( \\log\\frac{x}{y} = \\log x - \\log y \\)", "\\( \\log_a x = y \\iff a^y = x \\)", "\\( 4 \\)"]}'::jsonb, '{"answer": 1, "explain": "“Quotient law” means: \\( \\log\\frac{x}{y} = \\log x - \\log y \\)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:match:3960d847', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Power law”?", "options": ["\\( \\log 4 \\)", "\\( 2 \\)", "\\( \\log(x^n) = n\\log x \\)", "\\( \\log(xy) = \\log x + \\log y \\)"]}'::jsonb, '{"answer": 2, "explain": "“Power law” means: \\( \\log(x^n) = n\\log x \\)"}'::jsonb),
