('additional-maths:7-2-logarithms-and-the-log-laws:match:364ada24', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\log_{10} 100 \\)”?", "options": ["\\( 1 \\)", "\\( \\log 20 \\)", "\\( \\log 9 \\)", "\\( 2 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( \\log_{10} 100 \\)” means: \\( 2 \\)"}'::jsonb),
('additional-maths:7-2-logarithms-and-the-log-laws:match:3c8d4d88', 'additional-maths', 'additional-maths:7-2-logarithms-and-the-log-laws', '7.2 Logarithms and the Log Laws', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\log_5 125 \\)”?", "options": ["\\( 1 \\)", "\\( \\log\\frac{x}{y} = \\log x - \\log y \\)", "\\( \\log 20 \\)", "\\( 3 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( \\log_5 125 \\)” means: \\( 3 \\)"}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:c440725c', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Solve \\( 2^x = 15 \\), giving your answer to 3 s.f.", "options": ["\\( 3.91 \\)", "\\( 7.5 \\)", "\\( 0.256 \\)", "\\( 30 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\frac{\\log 15}{\\log 2} = 3.9069\\ldots = 3.91 \\). (\\( 15\\div 2 = 7.5 \\) ignores the power; \\( \\frac{\\log 2}{\\log 15} = 0.256 \\) inverts the fraction.)"}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:f047f137', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Solve \\( 10^x = 500 \\), to 3 s.f.", "options": ["\\( 2.70 \\)", "\\( 50 \\)", "\\( 0.370 \\)", "\\( 250 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\log_{10} 500 = 2.6989\\ldots = 2.70 \\). Base 10 is on your calculator directly."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:44b73048', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Solve \\( 5^x = 2 \\), to 3 s.f.", "options": ["\\( 0.431 \\)", "\\( 2.32 \\)", "\\( 0.400 \\)", "\\( 2.50 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\frac{\\log 2}{\\log 5} = 0.4307\\ldots = 0.431 \\). \\( \\frac{\\log 5}{\\log 2} = 2.32 \\) is the inverted (wrong) fraction."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:387bb947', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Solve \\( 3\\times 2^x = 48 \\).", "options": ["\\( 4 \\)", "\\( 5.58 \\)", "\\( 16 \\)", "\\( 8 \\)"]}'::jsonb, '{"answer": 0, "explain": "Divide by 3 first: \\( 2^x = 16 \\Rightarrow x = 4 \\). Taking \\( \\frac{\\log 48}{\\log 2} = 5.58 \\) forgets to divide by 3 first."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:583186b2', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Solve \\( 100\\times(0.5)^x = 25 \\).", "options": ["\\( 2 \\)", "\\( 4 \\)", "\\( -2 \\)", "\\( 0.5 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (0.5)^x = 0.25 = (0.5)^2 \\), so \\( x = 2 \\). Or \\( x = \\frac{\\log 0.25}{\\log 0.5} = 2 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:354618c9', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "What is the correct first step to solve \\( 4\\times 3^x = 100 \\)?", "options": ["Divide both sides by 4 to isolate \\( 3^x \\)", "Take the logarithm of the 4", "Multiply both sides by 3", "Subtract 4 from both sides"]}'::jsonb, '{"answer": 0, "explain": "Isolate the power: \\( 3^x = 25 \\). Then take logs: \\( x = \\frac{\\log 25}{\\log 3} = 2.93 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:7f24657c', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "A student solves \\( 2^x = 15 \\) by writing \\( x\\log 2 = 15 \\). What went wrong?", "options": ["They took logs of one side only — it should be \\( x\\log 2 = \\log 15 \\)", "Nothing — it is correct", "They should have written \\( x = 15\\log 2 \\)", "The base should be 10"]}'::jsonb, '{"answer": 0, "explain": "Logs must be taken of BOTH sides: \\( \\log(2^x) = \\log 15 \\Rightarrow x\\log 2 = \\log 15 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:82095fb1', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "A quantity grows by \\( 3\\% \\) a year: \\( V = V_0(1.03)^t \\). Its doubling time (3 s.f.) is:", "options": ["\\( 23.4 \\) years", "\\( 0.667 \\) years", "\\( 66.7 \\) years", "\\( 2 \\) years"]}'::jsonb, '{"answer": 0, "explain": "\\( (1.03)^t = 2 \\Rightarrow t = \\frac{\\log 2}{\\log 1.03} = 23.4 \\) years, independent of \\( V_0 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:e2fc3b28', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Why should you keep full calculator accuracy until the final step?", "options": ["Rounding intermediate values can change the last significant figure of the answer", "It makes the working look longer", "Logs only work with rounded numbers", "The calculator requires it"]}'::jsonb, '{"answer": 0, "explain": "Rounding \\( \\log 15,\\ \\log 2 \\) early can shift the final figure; round only the final answer."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:b4f2fac4', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "A radioactive sample is \\( M = 50\\times(0.9)^t \\) grams after \\( t \\) days. Find \\( M \\) after 5 days.", "options": ["\\( 29.5 \\) g", "\\( 45 \\) g", "\\( 25 \\) g", "\\( 32.8 \\) g"]}'::jsonb, '{"answer": 0, "explain": "\\( M = 50\\times(0.9)^5 = 50\\times 0.59049 = 29.5 \\) g. (No logs needed — just substitute.)"}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:5957c9ee', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "For \\( a^x = b \\) with \\( a > 1 \\) and \\( b > 1 \\), the solution \\( x \\) is:", "options": ["Positive", "Negative", "Always zero", "Impossible to find"]}'::jsonb, '{"answer": 0, "explain": "\\( \\log b \\) and \\( \\log a \\) are both positive, so \\( x = \\frac{\\log b}{\\log a} > 0 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:mcq:b19a37ba', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'mcq', 'mcq', 1, '{"question": "Give the EXACT solution of \\( 2^x = 15 \\).", "options": ["\\( x = \\frac{\\log 15}{\\log 2} \\)", "\\( x = 3.91 \\)", "\\( x = \\log(15 - 2) \\)", "\\( x = \\frac{15}{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "\"Exact\" means leave it as \\( \\frac{\\log 15}{\\log 2} \\) (equivalently \\( \\log_2 15 \\)); \\( 3.91 \\) is a rounded decimal."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:03fd9dce', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "To solve \\( a^x = b \\) you calculate \\( x = \\frac{\\log b}{\\log a} \\)."}'::jsonb, '{"answer": true, "explain": "Take logs of both sides and use the power law: \\( x\\log a = \\log b \\), so \\( x = \\frac{\\log b}{\\log a} \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:ef9345a2', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "To solve \\( 2^x = 15 \\) you work out \\( 15 \\div 2 = 7.5 \\)."}'::jsonb, '{"answer": false, "explain": "Dividing does not undo a power. You must take logs: \\( x = \\frac{\\log 15}{\\log 2} = 3.91 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:e3696505', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "\\( \\frac{\\log 15}{\\log 2} \\) is the same as \\( \\log\\!\\left(\\frac{15}{2}\\right) \\)."}'::jsonb, '{"answer": false, "explain": "A quotient of two logs is NOT the log of a quotient. \\( \\frac{\\log 15}{\\log 2} = 3.91 \\) but \\( \\log(7.5) = 0.875 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:dda8a09f', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "One valid way to solve \\( 5\\times 2^x = 3 \\) is to take logs of both sides and use \\( \\log(5\\times 2^x) = \\log 5 + x\\log 2 \\)."}'::jsonb, '{"answer": true, "explain": "The product and power laws give \\( \\log 5 + x\\log 2 = \\log 3 \\), which solves correctly. Isolating first is usually tidier."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:022162b3', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "Rounding \\( \\log 15 \\) and \\( \\log 2 \\) to 2 decimal places before dividing can change the last significant figure of the answer."}'::jsonb, '{"answer": true, "explain": "Early rounding accumulates error; keep full accuracy and round only at the end."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:da0955b2', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "An exponential decay curve eventually reaches exactly zero."}'::jsonb, '{"answer": false, "explain": "The horizontal axis is an asymptote: the curve gets ever closer to \\( y = 0 \\) but never touches it."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:d8a70de0', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "The half-life of a substance is the same length whatever amount you start with."}'::jsonb, '{"answer": true, "explain": "The starting amount \\( A_0 \\) cancels when you divide, so the half-life is independent of it."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tf:8d51bfe8', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tf', 'tf', 1, '{"question": "Every exponential equation \\( k a^x = b \\) needs logs, even \\( 2^x = 16 \\)."}'::jsonb, '{"answer": false, "explain": "When the answer is a whole-number power you can solve by inspection: \\( 2^x = 16 = 2^4 \\Rightarrow x = 4 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:8f4a8138', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve \\( a^x = b \\) by taking logs?", "reading": "<p>When the unknown is stuck in the <strong>exponent</strong>, you cannot get at it by ordinary algebra — you have to <strong>take the logarithm of both sides</strong>. The key move uses the <strong>power law</strong> \\( \\log(a^x) = x\\log a \\), which brings the \\( x \\) down to the front where you can divide it out.</p>\n            <p>The general result is: \\[ a^x = b \\quad\\Rightarrow\\quad x = \\frac{\\log b}{\\log a}. \\]</p>\n            <p><strong>Worked example — solve \\( 3^x = 20 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Take logs of <em>both</em> sides: \\( \\log(3^x) = \\log 20 \\).</td></tr>\n              <tr><td>2. Bring the power down (power law): \\( x\\log 3 = \\log 20 \\).</td></tr>\n              <tr><td>3. Divide by \\( \\log 3 \\): \\( x = \\dfrac{\\log 20}{\\log 3} \\).</td></tr>\n              <tr><td>4. Evaluate: \\( x = 2.7268\\ldots = 2.73 \\) (3 s.f.).</td></tr>\n            </table>\n            <p>Any base of log works (your calculator has \\( \\log_{10} \\) and \\( \\ln \\)) — you get the same answer. Notice it is \\( \\log b \\) <strong>divided by</strong> \\( \\log a \\), <em>not</em> \\( \\log(b \\div a) \\).</p>", "question": "Solve \\( 4^x = 30 \\), to 3 s.f.", "options": ["\\( 2.45 \\)", "\\( 7.5 \\)", "\\( 0.407 \\)", "\\( 1.48 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\frac{\\log 30}{\\log 4} = 2.4534\\ldots = 2.45 \\). (\\( 30\\div 4 = 7.5 \\) ignores the power; \\( \\frac{\\log 4}{\\log 30} = 0.407 \\) inverts the fraction.)"}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:e9eaf745', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve equations like \\( k\\times a^x = b \\)?", "reading": "<p>When there is a number multiplying the power, first <strong>isolate the power</strong> by dividing both sides by that number, then take logs as before.</p>\n            <p><strong>Worked example — solve \\( 5\\times 3^x = 60 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Divide both sides by \\( 5 \\): \\( 3^x = 12 \\).</td></tr>\n              <tr><td>2. Take logs and bring the power down: \\( x\\log 3 = \\log 12 \\).</td></tr>\n              <tr><td>3. Divide: \\( x = \\dfrac{\\log 12}{\\log 3} = 2.2619\\ldots = 2.26 \\) (3 s.f.).</td></tr>\n            </table>\n            <p>The same works for a <strong>decay</strong> base (\\( 0 < a < 1 \\)). <strong>Solve \\( 200\\times(0.8)^x = 50 \\):</strong> divide by 200 to get \\( (0.8)^x = 0.25 \\), then \\( x = \\dfrac{\\log 0.25}{\\log 0.8} = 6.21 \\) (3 s.f.). Here both logs are negative, and a negative divided by a negative is positive — so a shrinking quantity still takes a positive number of steps to reach a target.</p>\n            <p><em>Alternative:</em> you may instead take logs of \\( 5\\times 3^x = 60 \\) straight away and use \\( \\log(5\\times 3^x) = \\log 5 + x\\log 3 \\) (product + power laws). Isolating first is usually cleaner.</p>", "question": "First step to solve \\( 4\\times 2^x = 100 \\)?", "options": ["Divide both sides by 4 to isolate \\( 2^x \\)", "Take the log of the 4 only", "Work out \\( 100 \\div 2 = 50 \\)", "Subtract 4 from both sides"]}'::jsonb, '{"answer": 0, "explain": "Isolate the power first: \\( 2^x = 25 \\). Then \\( x = \\frac{\\log 25}{\\log 2} = 4.64 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:d68e1565', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you set up an exponential growth or decay model?", "reading": "<p>Many real quantities change by a fixed <strong>multiplier</strong> each time period — money in a savings account, a population, the mass of a decaying substance. These are modelled by \\[ A = A_0\\,a^t, \\] where \\( A_0 \\) is the <strong>starting amount</strong> (at \\( t = 0 \\)), \\( a \\) is the <strong>multiplier per period</strong>, and \\( t \\) is the time.</p>\n            <ul>\n              <li>\\( a > 1 \\) gives <strong>growth</strong> — e.g. a \\( 3\\% \\) yearly rise means \\( a = 1.03 \\).</li>\n              <li>\\( 0 < a < 1 \\) gives <strong>decay</strong> — e.g. losing \\( 15\\% \\) per year means \\( a = 0.85 \\).</li>\n              <li>Putting \\( t = 0 \\) always gives \\( A = A_0 \\); the graph cuts the vertical axis at \\( (0,\\ A_0) \\) and has the horizontal axis as an <strong>asymptote</strong> — it never actually reaches zero.</li>\n            </ul>\n            <p><strong>Compound interest is the classic example:</strong> £2000 invested at \\( 3\\% \\) per year grows to \\( A = 2000\\times(1.03)^t \\) pounds after \\( t \\) years.</p>", "question": "A car worth £12000 loses 18% of its value each year. Which model fits?", "options": ["\\( V = 12000\\times(0.82)^t \\)", "\\( V = 12000\\times(1.18)^t \\)", "\\( V = 12000\\times(0.18)^t \\)", "\\( V = 12000 - 0.18t \\)"]}'::jsonb, '{"answer": 0, "explain": "Losing 18% keeps 82%, so the yearly multiplier is \\( 0.82 \\); it is decay, so \\( 0 < a < 1 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:86bc5dd0', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you find the TIME to reach a given amount?", "reading": "<p>This is the commonest applied question: you are given a model and a target amount, and asked <em>when</em> it is reached. Substitute the target, <strong>isolate the power</strong>, then <strong>take logs</strong>.</p>\n            <p><strong>Worked example.</strong> A bacterial colony is modelled by \\( N = 500\\times(1.2)^t \\), where \\( t \\) is in hours. After how long does it reach \\( 2000 \\)?</p>\n            <table class=\"worked\">\n              <tr><td>1. Set \\( N = 2000 \\): \\( 500\\times(1.2)^t = 2000 \\).</td></tr>\n              <tr><td>2. Divide by 500 to isolate the power: \\( (1.2)^t = 4 \\).</td></tr>\n              <tr><td>3. Take logs, bring the power down: \\( t\\log 1.2 = \\log 4 \\).</td></tr>\n              <tr><td>4. Divide: \\( t = \\dfrac{\\log 4}{\\log 1.2} = 7.60 \\) hours (3 s.f.).</td></tr>\n            </table>\n            <p>To find a <strong>remaining amount</strong> instead of a time, you don''t need logs at all — just substitute the time. For \\( M = 80\\times(0.85)^t \\) grams, after \\( 10 \\) years \\( M = 80\\times(0.85)^{10} = 15.7 \\) g (3 s.f.).</p>", "question": "For \\( P = 3000\\times(1.05)^t \\), which equation finds when \\( P = 6000 \\)?", "options": ["\\( (1.05)^t = 2 \\)", "\\( (1.05)^t = 6000 \\)", "\\( (1.05)^t = 3000 \\)", "\\( 1.05t = 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "Divide \\( 6000 \\) by \\( 3000 \\) to isolate the power: \\( (1.05)^t = 2 \\), then \\( t = \\frac{\\log 2}{\\log 1.05} \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:046366af', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "What are half-life and doubling time?", "reading": "<p>Two special \"time to reach an amount\" questions have their own names:</p>\n            <ul>\n              <li><strong>Half-life</strong> — for a <em>decaying</em> quantity, the time taken to fall to <strong>half</strong> its value. You solve \\( a^t = \\tfrac{1}{2} \\).</li>\n              <li><strong>Doubling time</strong> — for a <em>growing</em> quantity, the time taken to become <strong>twice</strong> as large. You solve \\( a^t = 2 \\).</li>\n            </ul>\n            <p>A neat feature: both are <strong>independent of the starting amount</strong> — the \\( A_0 \\) cancels when you divide, so the half-life of a sample is the same whether you start with 1 kg or 1 g.</p>\n            <p><strong>Worked example — half-life for \\( M = M_0\\times(0.85)^t \\) (years):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Half the amount: \\( M_0\\times(0.85)^t = \\tfrac{1}{2}M_0 \\).</td></tr>\n              <tr><td>2. Divide by \\( M_0 \\): \\( (0.85)^t = 0.5 \\).</td></tr>\n              <tr><td>3. Logs: \\( t = \\dfrac{\\log 0.5}{\\log 0.85} = 4.27 \\) years (3 s.f.).</td></tr>\n            </table>", "question": "An investment grows by \\( 5\\% \\) a year, so \\( a = 1.05 \\). Its doubling time solves:", "options": ["\\( (1.05)^t = 2 \\)", "\\( (1.05)^t = 0.5 \\)", "\\( (1.05)^t = 5 \\)", "\\( 1.05^t = 100 \\)"]}'::jsonb, '{"answer": 0, "explain": "Doubling means twice the amount, so \\( (1.05)^t = 2 \\), giving \\( t = \\frac{\\log 2}{\\log 1.05} = 14.2 \\) years."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:learn:b995ce91', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'learn', 'mcq', 1, '{"readingTitle": "How accurate should your answer be?", "reading": "<p>Exponential answers are almost always <strong>irrational</strong>, so the question tells you the precision it wants — usually <strong>3 significant figures</strong>. Two rules save marks:</p>\n            <ul>\n              <li><strong>Don''t round early.</strong> Keep the full value on your calculator (or store it) and round only at the <em>very last</em> step. Rounding \\( \\log 15 \\) and \\( \\log 2 \\) to 2 d.p. first can shift the last figure of the answer.</li>\n              <li><strong>Read the command word.</strong> \\\"Correct to 3 significant figures\\\" wants a decimal to that precision; \\\"exact\\\" wants the answer left as \\( \\dfrac{\\log 15}{\\log 2} \\) or \\( \\log_2 15 \\), <strong>not</strong> a decimal.</li>\n            </ul>\n            <p>If a question is answered by <strong>trial and improvement</strong> rather than logs, examiners note it rarely reaches the required accuracy and an \"analytical\" or \"algebraic\" instruction means the log method is compulsory.</p>", "question": "A question says \"solve algebraically, to 3 significant figures\". You should:", "options": ["Use logs and round only the final answer to 3 s.f.", "Use trial and improvement", "Leave the answer as an exact log expression", "Round every intermediate value to 2 d.p. first"]}'::jsonb, '{"answer": 0, "explain": "\"Algebraically\" requires the log method; keep full accuracy and round the final answer to 3 s.f."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:misc:c28db309', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Solving \\( 2^x = 15 \\) by working out \\( 15 \\div 2 = 7.5 \\)</p><p><strong>✅ The correct idea:</strong> Dividing does not release an exponent. A weak answer divides; a strong answer takes logs of both sides: \\( x\\log 2 = \\log 15 \\Rightarrow x = \\frac{\\log 15}{\\log 2} = 3.91 \\).</p>", "question": "Solve \\( 2^x = 15 \\) (3 s.f.).", "options": ["\\( 3.91 \\)", "\\( 7.5 \\)", "\\( 13 \\)", "\\( 30 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x = \\frac{\\log 15}{\\log 2} = 3.91 \\); dividing gives the wrong \\( 7.5 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:misc:ed420e3c', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Taking the log of only one side: \\( 2^x = 15 \\Rightarrow x\\log 2 = 15 \\)</p><p><strong>✅ The correct idea:</strong> Whatever you do to one side you must do to the other. A strong answer logs BOTH sides: \\( \\log(2^x) = \\log 15 \\Rightarrow x\\log 2 = \\log 15 \\).</p>", "question": "Take logs of both sides of \\( 2^x = 15 \\):", "options": ["\\( x\\log 2 = \\log 15 \\)", "\\( x\\log 2 = 15 \\)", "\\( x = 15\\log 2 \\)", "\\( 2x = \\log 15 \\)"]}'::jsonb, '{"answer": 0, "explain": "Log both sides, then bring the power down: \\( x\\log 2 = \\log 15 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:misc:4becb26f', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing \\( \\frac{\\log 15}{\\log 2} \\) as \\( \\log\\!\\left(\\frac{15}{2}\\right) = \\log 7.5 \\)</p><p><strong>✅ The correct idea:</strong> A division of two logs is not the log of a division. A strong answer divides the two log VALUES: \\( \\frac{1.176}{0.301} = 3.91 \\), not \\( \\log 7.5 = 0.875 \\).</p>", "question": "\\( \\frac{\\log 15}{\\log 2} \\) equals:", "options": ["\\( 3.91 \\)", "\\( \\log 7.5 \\)", "\\( 0.875 \\)", "\\( \\log 13 \\)"]}'::jsonb, '{"answer": 0, "explain": "Divide the values: \\( 1.176 \\div 0.301 = 3.91 \\). It is not \\( \\log(15/2) \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:misc:3d875d5f', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Rounding to \\( \\log 15 \\approx 1.18 \\) and \\( \\log 2 \\approx 0.30 \\) before dividing, giving \\( 3.93 \\)</p><p><strong>✅ The correct idea:</strong> Early rounding shifts the last figure. A strong answer keeps full accuracy (\\( 1.17609\\ldots \\div 0.30103\\ldots \\)) and only rounds the final result to \\( 3.91 \\).</p>", "question": "Why is \\( 3.93 \\) wrong here?", "options": ["The intermediate logs were rounded too early", "Logs cannot be divided", "\\( 2^x = 15 \\) has no solution", "The base should be 10"]}'::jsonb, '{"answer": 0, "explain": "Rounding \\( \\log 15,\\ \\log 2 \\) before dividing changes the last figure; keep full accuracy."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:misc:8d8128fd', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For \\( 5\\times 2^x = 3 \\), taking logs to get \\( \\log 5 \\times x\\log 2 = \\log 3 \\)</p><p><strong>✅ The correct idea:</strong> The log of a PRODUCT is a SUM, not a product: \\( \\log(5\\times 2^x) = \\log 5 + x\\log 2 \\). A strong answer either isolates first (\\( 2^x = 0.6 \\)) or uses the sum correctly.</p>", "question": "\\( \\log(5\\times 2^x) \\) equals:", "options": ["\\( \\log 5 + x\\log 2 \\)", "\\( \\log 5 \\times x\\log 2 \\)", "\\( x\\log 10 \\)", "\\( \\log 5 - x\\log 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "Product law: \\( \\log(MN) = \\log M + \\log N \\), so \\( \\log 5 + x\\log 2 \\)."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tips:74a73b0d', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show every step of the log method", "reading": "<p>For \"solve \\( \\frac{1}{5}\\times 2^x = 3 \\) algebraically\" [3], examiners award <strong>M1</strong> for rearranging to \\( 2^x = 15 \\), <strong>M1</strong> for correct use of logs (\\( x\\log 2 = \\log 15 \\)), <strong>A1</strong> for \\( x = 3.91 \\).</p><p>A bare \\( 3.91 \\) with no working scores only a special-case 2 out of 3 — and trial-and-improvement rarely reaches the required accuracy. Write each line so a slip costs one mark, not all three.</p>", "question": "Why write out the log working in full?", "options": ["To earn the method marks even if the final value slips", "It is optional and wastes time", "Logs need extra paper", "To hide the answer"]}'::jsonb, '{"answer": 0, "explain": "Method (M) marks reward the visible rearrange-and-log steps regardless of the final answer."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tips:c56a585b', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tips', 'mcq', 1, '{"readingTitle": "explain — Answer to the demanded precision", "reading": "<p><strong>0 marks:</strong> an answer to the wrong accuracy, or a trial-and-improvement value that misses 3 s.f.</p><p><strong>Full marks:</strong> \\( x = 3.91 \\) (3 s.f.), obtained by keeping the full value \\( 3.9069\\ldots \\) on the calculator and rounding only at the end. If \"exact\" is asked instead, leave \\( \\frac{\\log 15}{\\log 2} \\) or \\( \\log_2 15 \\).</p>", "question": "The question says \"to 3 significant figures\". You should give:", "options": ["\\( 3.91 \\)", "\\( \\frac{\\log 15}{\\log 2} \\)", "\\( 3.9 \\)", "\\( 3.907 \\)"]}'::jsonb, '{"answer": 0, "explain": "3 s.f. of \\( 3.9069\\ldots \\) is \\( 3.91 \\); the exact form is only wanted when the command word is \"exact\"."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:tips:0a8a5888', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'tips', 'mcq', 1, '{"readingTitle": "tip — Isolate the power before taking logs", "reading": "<p>With a coefficient in front (\\( k a^x = b \\)), a clean, low-risk route is: <strong>divide by \\( k \\)</strong> to get \\( a^x = \\frac{b}{k} \\), <strong>then</strong> take logs. This avoids the classic slip of turning \\( \\log(k a^x) \\) into \\( \\log k \\times x\\log a \\) instead of the correct sum \\( \\log k + x\\log a \\).</p>", "question": "For \\( 5\\times 2^x = 3 \\), the safest first move is:", "options": ["Divide by 5 to get \\( 2^x = 0.6 \\)", "Multiply by 5", "Write \\( \\log 5 \\times x\\log 2 \\)", "Square both sides"]}'::jsonb, '{"answer": 0, "explain": "Isolating the power first (\\( 2^x = 0.6 \\)) avoids product-law errors."}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:fib:5fdb6030', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'fib', 'fib', 3, '{"question": "To solve \\( a^x = b \\) you take the ___B1___ of both sides. Using the power law this gives \\( x\\log a = \\log b \\), so \\( x \\) equals log ___B2___ divided by log ___B3___.", "blankOptions": {"B1": ["isolate", "logarithm", "first", "exact"], "B2": ["b", "first", "subtract", "5"], "B3": ["half-life", "3.91", "a", "subtract"]}}'::jsonb, '{"blanks": {"B1": "logarithm", "B2": "b", "B3": "a"}}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:fib:ddfaa7d9', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'fib', 'fib', 2, '{"question": "Before solving \\( 5\\times 2^x = 3 \\) it is cleanest to ___B1___ the power by dividing both sides by ___B2___.", "blankOptions": {"B1": ["isolate", "half-life", "last", "less"], "B2": ["first", "greater", "5", "last"]}}'::jsonb, '{"blanks": {"B1": "isolate", "B2": "5"}}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:fib:e1f5c8ff', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'fib', 'fib', 2, '{"question": "In the model \\( A = A_0 a^t \\), there is growth when \\( a \\) is ___B1___ than 1 and decay when \\( a \\) lies between 0 and ___B2___.", "blankOptions": {"B1": ["b", "doubling", "greater", "half-life"], "B2": ["3.91", "5", "subtract", "1"]}}'::jsonb, '{"blanks": {"B1": "greater", "B2": "1"}}'::jsonb),
('additional-maths:7-3-solving-exponential-equations:fib:4560e5c8', 'additional-maths', 'additional-maths:7-3-solving-exponential-equations', '7.3 Solving Exponential Equations', 'fib', 'fib', 1, '{"question": "The ___B1___ of a decaying quantity is the time it takes to fall to half its value.", "blankOptions": {"B1": ["a", "half-life", "round", "exact"]}}'::jsonb, '{"blanks": {"B1": "half-life"}}'::jsonb)
